// Compute whether the supplied nav item should be highlighted given the
// current pathname and role prefix.  `exact` means require an exact match
// (used for the dashboard so it doesn't claim every URL under the prefix).
function isItemActive(item, pathname, prefix) {
  const segments = (item.match && item.match.length > 0)
    ? item.match
    : [item.to];
  for (const seg of segments) {
    const target = `${prefix}/${seg.replace(/^\/+/, '')}`.replace(/\/+$/, '');
    if (item.exact) {
      if (pathname === target) return true;
    } else {
      if (pathname === target || pathname.startsWith(target + '/')) return true;
    }
  }
  return false;
}

export default function Sidebar() {
  const { role, isManager, isBsa, currentAnalyst, isL1, currentUser } = useRole();
  const { makePath, prefix } = useRoleNavigate();
  const location = useLocation();
  const [pendingApprovals, setPendingApprovals] = useState(0);
  const [overdueReviews, setOverdueReviews] = useState(0);
  const [myAssignedReviews, setMyAssignedReviews] = useState(0);

  useEffect(() => {
    let cancelled = false;
    const load = async () => {
      try {
        if (isManager || isBsa) {
          const [{ data: sar }, { data: kyc }] = await Promise.all([
            api.get('/sar-approvals/stats'),
            api.get('/kyc-reviews/stats')
          ]);
          if (!cancelled) {
            setPendingApprovals(sar.pending || 0);
            setOverdueReviews(kyc.overdue || 0);
          }
        } else if (currentAnalyst) {
          const { data } = await api.get('/kyc-reviews', {
            params: { assigned_to: currentAnalyst, status: 'in_progress' }
          });
          if (!cancelled) setMyAssignedReviews((data || []).length);
        }
      } catch (_e) { /* keep last value */ }
    };
    load();
    const id = setInterval(load, 30000);
    const onFocus = () => load();
    window.addEventListener('focus', onFocus);
    return () => { cancelled = true; clearInterval(id); window.removeEventListener('focus', onFocus); };
  }, [isManager, isBsa, currentAnalyst]);

  const badges = { pendingApprovals, overdueReviews, myAssignedReviews };
  const sections = isBsa
    ? BSA_SECTIONS
    : isManager
      ? MANAGER_SECTIONS
      : (isL1 ? EMPLOYEE_L1_SECTIONS : EMPLOYEE_L2_SECTIONS);

  return (
    <aside className="w-64 shrink-0 bg-navy-900 text-slate-200 flex flex-col h-screen sticky top-0">
      <div className="flex items-center gap-2 px-5 py-5 border-b border-navy-800">
        <CroweArcLogo size={36} />
        <div className="min-w-0">
          <div className="text-white font-semibold leading-tight">Crowe ARC</div>
          <div className="text-[11px] text-slate-400 leading-tight">
            Alert Review &amp; Casework
          </div>
          {isBsa && (
            <div className="mt-1 inline-flex items-center px-1.5 py-0.5 text-[9px] font-bold uppercase tracking-wider rounded"
                 style={{ backgroundColor: '#0EA5E9', color: '#FFFFFF' }}>
              BSA Officer
            </div>
          )}
        </div>
      </div>
      <nav className="flex-1 overflow-y-auto py-4">
        {sections.map((section) => (
          <div key={section.title} className="px-3 mb-5">
            <div className="text-[10px] font-semibold text-slate-500 tracking-wider px-3 mb-2">
              {section.title}
            </div>
            <ul className="space-y-0.5">
              {section.items.map((it) => {
                const Icon = it.icon;
                const badgeVal = it.badge ? badges[it.badge] : 0;
                const active = isItemActive(it, location.pathname, prefix);
                const accentColor = isManager ? 'bg-indigo-600' : 'bg-blue-600';
                const accentBorder = isManager ? 'border-indigo-400' : 'border-blue-400';
                return (
                  <li key={it.label + it.to}>
                    <NavLink
                      to={makePath(it.to)}
                      end={it.exact === true}
                      className={`relative flex items-center gap-3 text-sm rounded-md pl-3 pr-3 py-2 border-l-[3px] transition-colors ${
                        active
                          ? `${accentColor} ${accentBorder} text-white`
                          : 'border-transparent text-slate-300 hover:bg-navy-800 hover:text-white'
                      }`}
                    >
                      <Icon size={16} />
                      <span className="flex-1">{it.label}</span>
                      {badgeVal > 0 && (
                        <span className="text-[10px] font-semibold bg-red-500 text-white rounded-full px-1.5 py-0.5 min-w-[18px] text-center">
                          {badgeVal}
                        </span>
                      )}
                    </NavLink>
                  </li>
                );
              })}
            </ul>
          </div>
        ))}
      </nav>
      <div className="border-t border-navy-800 px-5 pt-4 pb-3">
        <img
          src="data:image/png;base64,"
          alt="Crowe"
          draggable={false}
          className="h-12 w-auto object-contain"
        />
        <div className="mt-2 text-xs text-slate-500">v1.3 · {role}</div>
      </div>
    </aside>
  );
}
